#include <bits/stdc++.h>
using namespace std;
const int maxn=1e4+6e3+5;
int n,dp[maxn],a[maxn],flag[maxn],root,ans=INT_MIN;
vector<int> g[maxn];
void dfs(int u,int fa){
	for(auto v:g[u]){
		if(v==fa){
			continue;
		}
		dfs(v,u);
		dp[u]+=max(dp[v],0);
	}
}
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>dp[i];
	}
	for(int i=1; i<n; i++) {
		int a,b;
		cin>>a>>b;
		g[a].emplace_back(b);
		g[b].emplace_back(a);
		flag[b]=1;
	}
	for(int i=1;i<=n;i++){
		if(!flag[i]){
			root=i;
		}
	}
	dfs(root,0);
	for(int i=1;i<=n;i++){
		ans=max(ans,dp[i]);
	}
	cout<<ans;
	return 0;
}
